import { Component, OnInit } from '@angular/core';
import { ComplaintService } from '../../services/complaint.service';
import { AuthService } from '../../services/auth.service';
import { Complaint } from '../../models/complaint.model';

@Component({
  selector: 'app-complaints',
  templateUrl: './complaints.component.html',
  styleUrls: ['./complaints.component.css']
})
export class ComplaintsComponent implements OnInit {
  complaints: Complaint[] = [];
  currentUser: any;
  showForm = false;
  newComplaint: Complaint = { studentId: 0, studentName: '', title: '', description: '', status: 'PENDING', priority: 'MEDIUM' };

  constructor(private complaintService: ComplaintService, private authService: AuthService) {}

  ngOnInit() {
    this.currentUser = this.authService.getCurrentUser();
    this.loadComplaints();
  }

  loadComplaints() {
    if (this.currentUser.role === 'STUDENT') {
      this.complaintService.getComplaintsByStudent(this.currentUser.id).subscribe(data => this.complaints = data);
    } else {
      this.complaintService.getAllComplaints().subscribe(data => this.complaints = data);
    }
  }

  createComplaint() {
    this.newComplaint.studentId = this.currentUser.id;
    this.newComplaint.studentName = this.currentUser.firstName + ' ' + this.currentUser.lastName;
    this.complaintService.createComplaint(this.newComplaint).subscribe(() => {
      this.loadComplaints();
      this.showForm = false;
      this.newComplaint = { studentId: 0, studentName: '', title: '', description: '', status: 'PENDING', priority: 'MEDIUM' };
      alert('Complaint submitted!');
    });
  }

  deleteComplaint(id: number) {
    if(confirm('Delete?')) {
      this.complaintService.deleteComplaint(id).subscribe(() => this.loadComplaints());
    }
  }
}
<div class="content-wrapper">
  <div class="container-fluid">
    <div class="d-flex justify-content-between mb-4">
      <h2>Complaints</h2>
      <button class="btn btn-primary" *ngIf="currentUser?.role === 'STUDENT'" (click)="showForm = !showForm">
        {{ showForm ? 'Cancel' : '+ New Complaint' }}
      </button>
    </div>

    <div *ngIf="showForm" class="card mb-4">
      <div class="card-body">
        <form (ngSubmit)="createComplaint()">
          <div class="mb-3">
            <label class="form-label">Title</label>
            <input type="text" class="form-control" [(ngModel)]="newComplaint.title" name="title" required>
          </div>
          <div class="mb-3">
            <label class="form-label">Description</label>
            <textarea class="form-control" [(ngModel)]="newComplaint.description" name="description" rows="3" required></textarea>
          </div>
          <div class="mb-3">
            <label class="form-label">Priority</label>
            <select class="form-control" [(ngModel)]="newComplaint.priority" name="priority">
              <option value="LOW">Low</option>
              <option value="MEDIUM">Medium</option>
              <option value="HIGH">High</option>
              <option value="URGENT">Urgent</option>
            </select>
          </div>
          <button type="submit" class="btn btn-success">Submit Complaint</button>
        </form>
      </div>
    </div>

    <div class="table-responsive">
      <table class="table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Student</th>
            <th>Title</th>
            <th>Priority</th>
            <th>Status</th>
            <th>Created</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let complaint of complaints">
            <td>{{ complaint.id }}</td>
            <td>{{ complaint.studentName }}</td>
            <td>{{ complaint.title }}</td>
            <td><span class="badge" [ngClass]="{'bg-danger': complaint.priority === 'URGENT', 'bg-warning': complaint.priority === 'HIGH', 'bg-info': complaint.priority === 'MEDIUM', 'bg-secondary': complaint.priority === 'LOW'}">
              {{ complaint.priority }}</span></td>
            <td><span class="badge" [ngClass]="{'bg-success': complaint.status === 'RESOLVED', 'bg-warning': complaint.status === 'PENDING', 'bg-primary': complaint.status === 'IN_PROGRESS'}">
              {{ complaint.status }}</span></td>
            <td>{{ complaint.createdAt | date:'short' }}</td>
            <td><button class="btn btn-sm btn-danger" (click)="deleteComplaint(complaint.id!)">Delete</button></td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
